        if (value === null || value === undefined) {
            return null;
        }
        var s = String(value).trim();
        if (s === '') {
            return null;
        }
        // Parens-as-negative MUST be detected before stripping the parens.
        var isParensNeg = false;
        if (s.charAt(0) === '(' && s.charAt(s.length - 1) === ')') {
            isParensNeg = true;
            s = s.slice(1, -1);
        }
