/* ===== assets/js/frontend/observers.js ===== */
/**
 * TableCrafter — frontend/observers.js
 *
 * Tabs / Accordion visibility observer (#77, #529) — extracted from
 * the monolithic frontend.js as the second module under #830.
 *
 * Closes #840.
 *
 * Surface: `GravityTable.prototype.initVisibilityObserver($wrapper)`.
 *
 * Three recovery paths, in order of preference:
 *
 *   1. IntersectionObserver — fires as soon as any pixel of the
 *      wrapper enters the viewport. Covers Gutenberg block tabs,
 *      native HTML5 details/summary, and most CSS-only reveals.
 *      One-shot: disconnects after the first reveal.
 *
 *   2. ResizeObserver — catches animated accordion height
 *      transitions that start at 0 height (IntersectionObserver
 *      may not fire for those because the wrapper has zero size).
 *      Fires adjustColumns only on the 0 -> >0 transition.
 *
 *   3. Public `gt:redraw` custom event (#529) — escape hatch for
 *      bespoke tab/accordion libraries (Bootstrap tabs, jQuery UI
 *      tabs, custom Elementor widgets) that swap visibility via
 *      mechanisms our two observers can't catch. Integrators
 *      dispatch the event from inside the wrapper:
 *
 *        // Native:
 *        wrapper.dispatchEvent(new CustomEvent('gt:redraw', { bubbles: true }));
 *        // jQuery:
 *        $wrapper.trigger('gt:redraw');
 *
 *      The handler calls `adjustColumns()`, the same code path the
 *      observers use, so all three recovery paths converge on a
 *      single re-measurement routine. Deliberately NOT one-shot —
 *      integrators may need to redraw on every subsequent tab
 *      change, not just the first.
 *
 * Defensive guards: if either observer API is missing from the host
 * environment (older browsers, jsdom), that recovery path is skipped
 * silently. If the wrapper has no underlying DOM element, the
 * function returns early — nothing to observe.
 */
(function (window) {
    'use strict';

    /* c8 ignore next 4 */
    if (typeof window.GravityTable !== 'function') {
        // Stub constructor; frontend.js preserves prototype on replace.
        window.GravityTable = function GravityTable() {};
    }

    Object.assign(window.GravityTable.prototype, {

        initVisibilityObserver: function ($wrapper) {
            var self = this;
            var el = $wrapper[0];
            if (!el) return;

            // 1. IntersectionObserver — fires once when the wrapper enters the viewport.
            if (typeof window.IntersectionObserver !== 'undefined') {
                var io = new window.IntersectionObserver(function (entries) {
                    entries.forEach(function (entry) {
                        if (entry.isIntersecting || entry.intersectionRatio > 0) {
                            self.adjustColumns();
                            io.disconnect();
                        }
                    });
                }, { threshold: 0.01 });
                io.observe(el);
            }

            // 2. ResizeObserver — catches 0 -> >0 height transitions.
            if (typeof window.ResizeObserver !== 'undefined') {
                var prevHeight = el.offsetHeight;
                var ro = new window.ResizeObserver(function () {
                    var h = el.offsetHeight;
                    if (prevHeight === 0 && h > 0) {
                        self.adjustColumns();
                    }
                    prevHeight = h;
                });
                ro.observe(el);
            }

            // 3. Public gt:redraw escape hatch.
            $wrapper.on('gt:redraw', function () {
                self.adjustColumns();
            });
        }

    });

})(window);

/* ===== assets/js/frontend/conditional-format.js ===== */
/**
 * TableCrafter — frontend/conditional-format.js
 *
 * Conditional formatting rule engine. Third module under #830.
 *
 * Closes #838.
 *
 * Surface (all attached to GravityTable.prototype via Object.assign):
 *   - applyConditionalFormatting()          — entry point, walks rows.
 *   - getColumnIndex(fieldId)               — string/number lookup
 *                                             with selection-checkbox
 *                                             offset adjustment.
 *   - getCellValue($cell, fieldId)          — extracts text from a
 *                                             cell, preferring inline
 *                                             editor content when set.
 *   - evaluateCondition(cellValue, op,
 *                       criteriaValue,
 *                       columnType)         — pure rule evaluator.
 *                                             Supports eq/neq/lt/lteq/
 *                                             gt/gteq/contains/
 *                                             contains_not/empty/
 *                                             not_empty.
 *   - applyFormattingAction($cell, $row,
 *                            action,
 *                            setValue)      — dispatcher for
 *                                             setCellColor /
 *                                             setCellContent /
 *                                             setCellClass /
 *                                             setRowColor / setRowClass.
 *
 * evaluateCondition is intentionally pure — it does no DOM access and
 * no jQuery calls — so the behavioral test suite can exercise every
 * operator with controlled inputs.
 */
(function (window) {
    'use strict';

    /* c8 ignore next 4 */
    if (typeof window.GravityTable !== 'function') {
        // Stub constructor; frontend.js preserves prototype on replace.
        window.GravityTable = function GravityTable() {};
    }

    var $ = window.jQuery || window.$;

    Object.assign(window.GravityTable.prototype, {

        applyConditionalFormatting: function () {
            var self = this;
            var $wrapper = $('#' + this.wrapperId);

            if (!this.config.column_config) {
                return;
            }

            // #1049 Option 2 v4.219.0 — hot-loop perf refactor. Behavior
            // unchanged (pinned by end-to-end vitest); just faster.
            // 1. Cache the tbody row list ONCE outside the outer loop
            //    (was re-queried per column_config entry).
            // 2. Use native iteration (forEach / for-of) instead of $.each.
            // 3. Use direct row.children[columnIndex] DOM access instead
            //    of $row.find('td').eq(columnIndex) (saves a jQuery
            //    selector parse + tree walk per cell).
            // 4. jQuery wrappers still constructed for the per-cell
            //    applyFormattingAction call since that helper expects $.
            var rowElements = $wrapper.find('tbody tr').toArray();
            if (rowElements.length === 0) {
                return;
            }
            var columnConfig = this.config.column_config;
            for (var fieldId in columnConfig) {
                if (!Object.prototype.hasOwnProperty.call(columnConfig, fieldId)) continue;
                var cfg = columnConfig[fieldId];
                if (!cfg.conditional_formatting || cfg.conditional_formatting.length === 0) continue;

                var columnIndex = self.getColumnIndex(fieldId);
                if (columnIndex === -1) continue;

                var rules = cfg.conditional_formatting;
                var cfgType = cfg.type;
                for (var i = 0, n = rowElements.length; i < n; i++) {
                    var rowEl = rowElements[i];
                    var cellEl = rowEl.children[columnIndex];
                    if (!cellEl) continue;
                    var $cell = $(cellEl);
                    var $row = $(rowEl);
                    var cellValue = self.getCellValue($cell, fieldId);
                    for (var r = 0, rn = rules.length; r < rn; r++) {
                        var rule = rules[r];
                        if (self.evaluateCondition(cellValue, rule.ifClause, rule.cellVal, cfgType)) {
                            self.applyFormattingAction($cell, $row, rule.action, rule.setVal);
                        }
                    }
                }
            }
        },

        getColumnIndex: function (fieldId) {
            var index = -1;
            if (this.config.columns) {
                var fieldIdStr = String(fieldId);
                index = this.config.columns.indexOf(fieldIdStr);

                if (index === -1) {
                    var fieldIdNum = parseInt(fieldId);
                    index = this.config.columns.indexOf(fieldIdNum);
                }

                if (index !== -1 && $('#' + this.wrapperId).find('.gt-selection-header').length > 0) {
                    index++;
                }
            }
            return index;
        },

        getCellValue: function ($cell, fieldId) {
            var value = $cell.find('.gt-editable-field').length > 0
                ? $cell.find('.gt-editable-field').text()
                : $cell.text();
            return value.trim();
        },

        evaluateCondition: function (cellValue, operator, criteriaValue, columnType) {
            if (cellValue === '' || cellValue === '&nbsp;') {
                cellValue = '';
            }

            var numericTypes = ['number', 'int', 'float'];
            if (numericTypes.includes(columnType)) {
                cellValue = parseFloat(cellValue) || 0;
                criteriaValue = parseFloat(criteriaValue) || 0;
            }

            switch (operator) {
                case 'empty':         return cellValue === '';
                case 'not_empty':     return cellValue !== '';
                case 'eq':            return cellValue == criteriaValue;
                case 'neq':           return cellValue != criteriaValue;
                case 'lt':            return cellValue < criteriaValue;
                case 'lteq':          return cellValue <= criteriaValue;
                case 'gt':            return cellValue > criteriaValue;
                case 'gteq':          return cellValue >= criteriaValue;
                case 'contains':      return cellValue.toString().toLowerCase().indexOf(criteriaValue.toLowerCase()) !== -1;
                case 'contains_not':  return cellValue.toString().toLowerCase().indexOf(criteriaValue.toLowerCase()) === -1;
                default:              return false;
            }
        },

        applyFormattingAction: function ($cell, $row, action, setValue) {
            switch (action) {
                case 'setCellColor':
                    // frontend.css line 802 forces td[style*="background-color"]
                    // to use var(--gt-cell-bg) via !important (for rowspan-merge
                    // bg coverage). Set both so the !important rule resolves to
                    // the intended color.
                    $cell.css({ 'background-color': setValue, '--gt-cell-bg': setValue });
                    break;
                case 'setCellContent':
                    if ($cell.find('.gt-editable-field').length > 0) {
                        $cell.find('.gt-editable-field').html(setValue);
                    } else {
                        $cell.html(setValue);
                    }
                    break;
                case 'setCellClass':
                    $cell.addClass(setValue);
                    break;
                case 'setRowColor':
                    $row.css('background-color', setValue);
                    break;
                case 'setRowClass':
                    $row.addClass(setValue);
                    break;
            }
        }

    });

})(window);

/* ===== assets/js/frontend/selection.js ===== */
/**
 * TableCrafter — frontend/selection.js
 *
 * Row selection state + bulk action toolbar wire-up. Fourth module
 * under #830.
 *
 * Closes #836.
 *
 * Surface (attached to GravityTable.prototype via Object.assign):
 *
 *   - bindSelectionEvents($wrapper)   — wires .gt-select-all change
 *                                       (toggle every gt-entry-checkbox)
 *                                       + .gt-bulk-action-btn click
 *                                       (delegates to performBulkAction
 *                                       when a non-empty action is
 *                                       selected). Called once from
 *                                       bindEvents in frontend.js.
 *
 *   - getSelectedEntryIds()           — collects values from every
 *                                       checked .gt-entry-checkbox
 *                                       inside the wrapper. Pure-DOM
 *                                       helper, no side effects.
 *
 *   - performBulkAction(action)       — collects selected ids; alerts
 *                                       and returns early when none;
 *                                       confirms on delete; POSTs to
 *                                       the gt_bulk_action AJAX
 *                                       endpoint; on success: alerts
 *                                       the response message, unchecks
 *                                       every checkbox (#130 — prevent
 *                                       stale selections after reload),
 *                                       reloads entries.
 *
 * Hot path note: getSelectedEntryIds is also reachable to any future
 * caller that needs the currently-checked rows without firing AJAX
 * (e.g. export "selected rows only", #836b future enhancement).
 */
(function (window) {
    'use strict';

    /* c8 ignore next 4 */
    if (typeof window.GravityTable !== 'function') {
        // Stub constructor; frontend.js preserves prototype on replace.
        window.GravityTable = function GravityTable() {};
    }

    var $ = window.jQuery || window.$;

    Object.assign(window.GravityTable.prototype, {

        bindSelectionEvents: function ($wrapper) {
            var self = this;

            $wrapper.find('.gt-select-all').on('change', function () {
                var checked = $(this).prop('checked');
                $wrapper.find('.gt-entry-checkbox').prop('checked', checked);
            });

            $wrapper.find('.gt-bulk-action-btn').on('click', function () {
                var action = $wrapper.find('.gt-bulk-action-select').val();
                if (action) {
                    self.performBulkAction(action);
                }
            });
        },

        getSelectedEntryIds: function () {
            var ids = [];
            var $wrapper = $('#' + this.wrapperId);
            $wrapper.find('.gt-entry-checkbox:checked').each(function () {
                ids.push($(this).val());
            });
            return ids;
        },

        performBulkAction: function (action) {
            var self = this;
            var $wrapper = $('#' + this.wrapperId);
            var selectedEntries = self.getSelectedEntryIds();

            if (selectedEntries.length === 0) {
                alert('Please select entries to perform bulk action');
                return;
            }

            // #613 phase 2 slice 5 (v4.200.0) — intercept push_to_source and
            // delegate to pushRowToSource per entry. Reads each row's current
            // values from its tbody cells (keyed by data-field-id) so the
            // payload reflects the user's latest inline edits.
            // #613 phase 2 slice 6 (v4.201.0) — aggregate success/failure
            // feedback. After all per-row pushes complete, surface a single
            // alert with success and failure counts so the user sees the
            // outcome (previously silent).
            if (action === 'push_to_source') {
                if (typeof self.pushRowToSource !== 'function') {
                    /* c8 ignore next */
                    return;
                }
                var total = selectedEntries.length;
                var completed = 0;
                var succeeded = 0;
                var failed = 0;
                selectedEntries.forEach(function (rowId) {
                    var $row = $wrapper.find('tbody tr[data-entry-id="' + rowId + '"]');
                    var payload = {};
                    $row.find('td[data-field-id]').each(function () {
                        var $td = $(this);
                        var fieldId = String($td.attr('data-field-id'));
                        payload[fieldId] = ($td.text() || '').trim();
                    });
                    self.pushRowToSource(rowId, payload, function (response) {
                        completed++;
                        // #613 phase 2 slice 7 (v4.202.0) — per-row visual
                        // feedback. Mark each row with a class so CSS can
                        // tint it; on failure, surface the typed error code
                        // via a title attribute the user can hover to read.
                        $row.removeClass('gt-push-success gt-push-failed');
                        if (response && response.success) {
                            succeeded++;
                            $row.addClass('gt-push-success');
                            $row.removeAttr('title');
                        } else {
                            failed++;
                            $row.addClass('gt-push-failed');
                            var errCode = (response && response.data && response.data.code) ? response.data.code : 'push_error';
                            var errMsg  = (response && response.data && response.data.message) ? response.data.message : 'Push failed.';
                            $row.attr('title', errCode + ': ' + errMsg);
                        }
                        if (completed === total) {
                            if (failed === 0) {
                                alert('Pushed ' + succeeded + ' row' + (succeeded === 1 ? '' : 's') + ' successfully.');
                            } else {
                                alert('Pushed ' + succeeded + ' row' + (succeeded === 1 ? '' : 's') + ', ' + failed + ' failed.');
                            }
                        }
                    });
                });
                return;
            }

            if (action === 'delete') {
                if (!confirm('Are you sure you want to delete ' + selectedEntries.length + ' entries?')) {
                    return;
                }
            }

            var data = {
                action: 'gt_bulk_action',
                nonce: this.config.nonce,
                bulk_action: action,
                entry_ids: selectedEntries,
                table_id: this.config.table_id || 0
            };

            $.post(this.config.ajax_url, data, function (response) {
                if (response.success) {
                    alert(response.data.message);
                    // Uncheck all checkboxes before reloading so stale selections do not persist (#130).
                    $wrapper.find('.gt-entry-checkbox').prop('checked', false);
                    self.loadEntries();
                } else {
                    alert('Error performing bulk action: ' + response.data);
                }
            }).fail(function () {
                /* c8 ignore next */
                alert('Error performing bulk action');
            });
        }

    });

})(window);

/* ===== assets/js/frontend/pagination.js ===== */
/**
 * TableCrafter — frontend/pagination.js
 *
 * Pagination controls + length selector. Fifth module under #830.
 *
 * Closes #835.
 *
 * Surface (attached to GravityTable.prototype via Object.assign):
 *
 *   - computeTotalPages(data, perPage)
 *       Pure helper. Returns the page count given an entries response
 *       envelope. Prefers data.total_pages from the server, falls back
 *       to Math.ceil(data.total / perPage), then 1. Issue #185 fixed
 *       a hard-coded 1 fallback that hid pagination permanently on
 *       2,000+ row responses; this helper preserves that behavior.
 *
 *   - formatPaginationInfoText(template, start, end, total)
 *       Pure helper. {start} / {end} / {total} token replacement.
 *       Used by updatePagination + reachable to any future consumer
 *       that wants to render the same info string elsewhere.
 *
 *   - bindPaginationEvents($wrapper)
 *       Wires the length-selector change handler + prev / next page
 *       click handlers (delegated, .gt-table namespace so the
 *       $wrapper.off('.gt-table') re-mount guard cleans them up — #128).
 *       Called once from bindEvents in frontend.js.
 *
 *   - updatePagination(data)
 *       Orchestrates the DOM update per AJAX response. Toggles the
 *       gt-pagination-single-page class on single-page responses
 *       (CSS-class hiding so the show_pagination table setting wins
 *       over the single-page check — #185). Updates entry-count text,
 *       current/total page text, prev/next disabled state.
 */
