            $wrapper.find('.gt-current-page').text(this.currentPage);
            $wrapper.find('.gt-total-pages').text('of ' + totalPages);

            var $prevBtn = $wrapper.find('.gt-prev-page');
            var $nextBtn = $wrapper.find('.gt-next-page');

