                    span.style.background    = bg;
                    span.style.color         = text;
                    span.style.borderRadius  = '9999px';
                    span.style.padding       = '2px 10px';
                    span.style.fontSize      = '.8em';
                    span.style.fontWeight    = '600';
                    span.style.display       = 'inline-block';
